{"action":"write","content":"const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const path = require('path');
const { getMetrics } = require('./metrics');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer);

const PORT = process.env.PORT || 3000;
const UPDATE_INTERVAL = process.env.UPDATE_INTERVAL_MS || 2000;

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Store connected clients count
let connectedClients = 0;
let metricsInterval = null;

// Function to broadcast metrics to all connected clients
async function broadcastMetrics() {
  try {
    const metrics = await getMetrics();
    io.emit('metrics', metrics);
  } catch (error) {
    console.error('Error broadcasting metrics:', error.message);
  }
}

// Start metrics broadcasting
function startMetricsBroadcast() {
  if (metricsInterval) return;

  console.log(`Starting metrics broadcast every ${UPDATE_INTERVAL}ms`);
  metricsInterval = setInterval(broadcastMetrics, UPDATE_INTERVAL);

  // Send initial metrics immediately
  broadcastMetrics();
}

// Stop metrics broadcasting
function stopMetricsBroadcast() {
  if (metricsInterval) {
    clearInterval(metricsInterval);
    metricsInterval = null;
    console.log('Stopped metrics broadcast');
  }
}

// Socket.io connection handling
io.on('connection', (socket) => {
  connectedClients++;
  console.log(`Client connected. Total clients: ${connectedClients}`);

  // Start broadcasting if this is the first client
  if (connectedClients === 1) {
    startMetricsBroadcast();
  }

  // Send current metrics immediately to new client
  broadcastMetrics();

  socket.on('disconnect', () => {
    connectedClients--;
    console.log(`Client disconnected. Total clients: ${connectedClients}`);

    // Stop broadcasting if no clients are connected
    if (connectedClients === 0) {
      stopMetricsBroadcast();
    }
  });
});

// Graceful shutdown
process.on('SIGTERM', () => {
  console.log('SIGTERM received, shutting down gracefully');
  stopMetricsBroadcast();
  httpServer.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

process.on('SIGINT', () => {
  console.log('SIGINT received, shutting down gracefully');
  stopMetricsBroadcast();
  httpServer.close(() => {
    console.log('Server closed');
    process.exit(0);
  });
});

// Start the server
httpServer.listen(PORT, () => {
  console.log(`Server is running on http://localhost:${PORT}`);
  console.log(`Metrics update interval: ${UPDATE_INTERVAL}ms`);
});

module.exports = { app, httpServer, io };
","path":"server.js"}

{"action":"write","content":"const os = require('os');

/**
 * Get current CPU usage statistics
 * @returns {Promise<Object>} CPU usage data
 */
async function getCPUUsage() {
  return new Promise((resolve) => {
    const cpus = os.cpus();
    const cpuCount = cpus.length;

    // Calculate average CPU load across all cores
    let totalIdle = 0;
    let totalTick = 0;

    cpus.forEach((cpu) => {
      for (const type in cpu.times) {
        totalTick += cpu.times[type];
      }
      totalIdle += cpu.times.idle;
    });

    // Wait a bit and measure again for load calculation
    const startIdle = totalIdle;
    const startTick = totalTick;

    setTimeout(() => {
      const cpus2 = os.cpus();
      let totalIdle2 = 0;
      let totalTick2 = 0;

      cpus2.forEach((cpu) => {
        for (const type in cpu.times) {
          totalTick2 += cpu.times[type];
        }
        totalIdle2 += cpu.times.idle;
      });

      const idleDiff = totalIdle2 - startIdle;
      const tickDiff = totalTick2 - startTick;
      const loadPercent = 100 - Math.floor((idleDiff / tickDiff) * 100);

      // Per-core usage
      const cores = cpus2.map((cpu, index) => {
        let coreTotal = 0;
        let coreIdle = cpu.times.idle;
        for (const type in cpu.times) {
          coreTotal += cpu.times[type];
        }
        return {
          core: index,
          load: Math.round(((coreTotal - coreIdle) / coreTotal) * 100 * 100) / 100
        };
      });

      resolve({
        overall: Math.max(0, Math.min(100, loadPercent)),
        cores: cores
      });
    }, 100);
  });
}

/**
 * Get current memory usage statistics
 * @returns {Promise<Object>} Memory usage data
 */
async function getMemoryUsage() {
  const total = os.totalmem();
  const free = os.freemem();
  const used = total - free;

  return {
    total: Math.round(total / 1024 / 1024), // MB
    used: Math.round(used / 1024 / 1024),   // MB
    free: Math.round(free / 1024 / 1024),   // MB
    usagePercent: Math.round((used / total) * 10000) / 100
  };
}

/**
 * Get both CPU and memory metrics in one call
 * @returns {Promise<Object>} Combined metrics data
 */
async function getMetrics() {
  const [cpu, memory] = await Promise.all([
    getCPUUsage(),
    getMemoryUsage()
  ]);

  return {
    timestamp: new Date().toISOString(),
    cpu,
    memory
  };
}

module.exports = {
  getCPUUsage,
  getMemoryUsage,
  getMetrics
};
