{"action":"write","content":"const si = require('systeminformation');

/**
 * Get current CPU usage statistics
 * @returns {Promise<Object>} CPU usage data
 */
async function getCPUUsage() {
  try {
    const load = await si.currentLoad();
    return {
      overall: Math.round(load.currentLoad * 100) / 100,
      cores: load.cpus.map((core, index) => ({
        core: index,
        load: Math.round(core.load * 100) / 100
      }))
    };
  } catch (error) {
    console.error('Error fetching CPU usage:', error.message);
    throw error;
  }
}

/**
 * Get current memory usage statistics
 * @returns {Promise<Object>} Memory usage data
 */
async function getMemoryUsage() {
  try {
    const mem = await si.mem();
    return {
      total: Math.round(mem.total / 1024 / 1024), // MB
      used: Math.round(mem.used / 1024 / 1024),    // MB
      free: Math.round(mem.free / 1024 / 1024),    // MB
      active: Math.round(mem.active / 1024 / 1024), // MB
      available: Math.round(mem.available / 1024 / 1024), // MB
      usagePercent: Math.round((mem.used / mem.total) * 10000) / 100
    };
  } catch (error) {
    console.error('Error fetching memory usage:', error.message);
    throw error;
  }
}

/**
 * Get both CPU and memory metrics in one call
 * @returns {Promise<Object>} Combined metrics data
 */
async function getMetrics() {
  try {
    const [cpu, memory] = await Promise.all([
      getCPUUsage(),
      getMemoryUsage()
    ]);
    return {
      timestamp: new Date().toISOString(),
      cpu,
      memory
    };
  } catch (error) {
    console.error('Error fetching metrics:', error.message);
    throw error;
  }
}

module.exports = {
  getCPUUsage,
  getMemoryUsage,
  getMetrics
};
","path":"metrics.js"}

