{"action":"write","content":"/**
 * Centralized configuration for the System Monitor application
 * Values can be overridden via environment variables
 */

const config = {
  // Server configuration
  PORT: parseInt(process.env.PORT, 10) || 3000,

  // Metrics update interval in milliseconds
  UPDATE_INTERVAL_MS: parseInt(process.env.UPDATE_INTERVAL_MS, 10) || 2000,

  // Maximum number of data points to keep in charts
  MAX_CHART_POINTS: parseInt(process.env.MAX_CHART_POINTS, 10) || 30,

  // Socket.io configuration
  SOCKET_CORS_ORIGIN: process.env.SOCKET_CORS_ORIGIN || '*',

  // Logging configuration
  LOG_LEVEL: process.env.LOG_LEVEL || 'info',

  // Metrics configuration
  METRICS_TIMEOUT_MS: parseInt(process.env.METRICS_TIMEOUT_MS, 10) || 5000
};

// Validation
if (config.UPDATE_INTERVAL_MS < 1000) {
  console.warn('UPDATE_INTERVAL_MS should be at least 1000ms. Using 1000ms.');
  config.UPDATE_INTERVAL_MS = 1000;
}

if (config.MAX_CHART_POINTS < 10) {
  console.warn('MAX_CHART_POINTS should be at least 10. Using 10.');
  config.MAX_CHART_POINTS = 10;
}

module.exports = config;
