{"action":"write","content":"const express = require('express');
const { createServer } = require('http');
const { Server } = require('socket.io');
const path = require('path');
const config = require('./config');
const { getMetrics } = require('./metrics');

const app = express();
const httpServer = createServer(app);
const io = new Server(httpServer, {
  cors: {
    origin: config.SOCKET_CORS_ORIGIN,
    methods: ['GET', 'POST']
  }
});

// Serve static files from the public directory
app.use(express.static(path.join(__dirname, 'public')));

// Store connected clients count
let connectedClients = 0;
let metricsInterval = null;

// Logging helper
function log(level, message, data = null) {
  const timestamp = new Date().toISOString();
  const logEntry = {
    timestamp,
    level,
    message,
    ...(data && { data })
  };

  if (config.LOG_LEVEL === 'debug' || level !== 'debug') {
    console.log(JSON.stringify(logEntry));
  }
}

// Function to broadcast metrics to all connected clients
async function broadcastMetrics() {
  try {
    const metrics = await getMetrics();
    io.emit('metrics', metrics);
    log('debug', 'Metrics broadcasted', { 
      cpu: metrics.cpu.overall, 
      memory: metrics.memory.usagePercent 
    });
  } catch (error) {
    log('error', 'Error broadcasting metrics', { error: error.message });
  }
}

// Start metrics broadcasting
function startMetricsBroadcast() {
  if (metricsInterval) return;

  log('info', `Starting metrics broadcast every ${config.UPDATE_INTERVAL_MS}ms`);
  metricsInterval = setInterval(broadcastMetrics, config.UPDATE_INTERVAL_MS);

  // Send initial metrics immediately
  broadcastMetrics();
}

// Stop metrics broadcasting
function stopMetricsBroadcast() {
  if (metricsInterval) {
    clearInterval(metricsInterval);
    metricsInterval = null;
    log('info', 'Stopped metrics broadcast');
  }
}

// Socket.io connection handling
io.on('connection', (socket) => {
  connectedClients++;
  log('info', 'Client connected', { 
    clientId: socket.id, 
    totalClients: connectedClients 
  });

  // Start broadcasting if this is the first client
  if (connectedClients === 1) {
    startMetricsBroadcast();
  }

  // Send current metrics immediately to new client
  broadcastMetrics();

  socket.on('disconnect', (reason) => {
    connectedClients--;
    log('info', 'Client disconnected', { 
      clientId: socket.id, 
      reason,
      totalClients: connectedClients 
    });

    // Stop broadcasting if no clients are connected
    if (connectedClients === 0) {
      stopMetricsBroadcast();
    }
  });

  socket.on('error', (error) => {
    log('error', 'Socket error', { 
      clientId: socket.id, 
      error: error.message 
    });
  });
});

// Graceful shutdown
function gracefulShutdown(signal) {
  log('info', `${signal} received, shutting down gracefully`);
  stopMetricsBroadcast();

  httpServer.close(() => {
    log('info', 'Server closed');
    process.exit(0);
  });

  // Force shutdown after 10 seconds
  setTimeout(() => {
    log('error', 'Forced shutdown after timeout');
    process.exit(1);
  }, 10000);
}

process.on('SIGTERM', () => gracefulShutdown('SIGTERM'));
process.on('SIGINT', () => gracefulShutdown('SIGINT'));

// Handle uncaught exceptions
process.on('uncaughtException', (error) => {
  log('error', 'Uncaught exception', { error: error.message, stack: error.stack });
  gracefulShutdown('UNCAUGHT_EXCEPTION');
});

// Handle unhandled promise rejections
process.on('unhandledRejection', (reason, promise) => {
  log('error', 'Unhandled promise rejection', { reason: reason?.message || reason });
});

// Start the server
httpServer.listen(config.PORT, () => {
  log('info', `Server is running on http://localhost:${config.PORT}`);
  log('info', `Configuration`, {
    port: config.PORT,
    updateInterval: config.UPDATE_INTERVAL_MS,
    maxChartPoints: config.MAX_CHART_POINTS,
    logLevel: config.LOG_LEVEL
  });
});

module.exports = { app, httpServer, io };
","path":"server.js"}

