const { io } = require('socket.io-client');
const socket = io('http://localhost:3000');
let count = 0;

socket.on('connect', () => {
  console.log('Connected to server');
});

socket.on('metrics', (data) => {
  count++;
  console.log('Update #' + count);
  console.log('  CPU Overall:', data.cpu.overall.toFixed(1) + '%');
  console.log('  Memory Used:', data.memory.used + ' MB');
  console.log('  Memory Usage:', data.memory.usagePercent.toFixed(1) + '%');

  if (count >= 3) {
    console.log('Received 3 updates successfully');
    socket.disconnect();
  }
});

socket.on('disconnect', () => {
  console.log('Disconnected from server');
  process.exit(0);
});

setTimeout(() => {
  console.log('Timeout - received ' + count + ' updates');
