<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>System Monitor Dashboard</title>
    <script src="https://cdn.jsdelivr.net/npm/chart.js@4.4.1/dist/chart.umd.min.js"></script>
    <script src="https://cdn.socket.io/4.7.4/socket.io.min.js"></script>
    <style>
        * {
            margin: 0;
            padding: 0;
            box-sizing: border-box;
        }

        body {
            font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', Roboto, Oxygen, Ubuntu, Cantarell, sans-serif;
            background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
            min-height: 100vh;
            padding: 20px;
        }

        .container {
            max-width: 1200px;
            margin: 0 auto;
        }

        header {
            text-align: center;
            margin-bottom: 30px;
            color: white;
        }

        h1 {
            font-size: 2.5rem;
            margin-bottom: 10px;
            text-shadow: 2px 2px 4px rgba(0,0,0,0.3);
        }

        .status {
            display: flex;
            justify-content: center;
            gap: 20px;
            margin-top: 15px;
            flex-wrap: wrap;
        }

        .status-badge {
            background: rgba(255,255,255,0.2);
            padding: 8px 16px;
            border-radius: 20px;
            font-size: 0.9rem;
            backdrop-filter: blur(10px);
        }

        .status-badge.connected {
            background: rgba(46, 204, 113, 0.3);
            border: 1px solid rgba(46, 204, 113, 0.5);
        }

        .status-badge.disconnected {
            background: rgba(231, 76, 60, 0.3);
            border: 1px solid rgba(231, 76, 60, 0.5);
        }

        .dashboard {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(500px, 1fr));
            gap: 20px;
            margin-bottom: 20px;
        }

        .card {
            background: white;
            border-radius: 15px;
            padding: 25px;
            box-shadow: 0 10px 30px rgba(0,0,0,0.2);
            transition: transform 0.3s ease;
        }

        .card:hover {
            transform: translateY(-5px);
        }

        .card-header {
            display: flex;
            justify-content: space-between;
            align-items: center;
            margin-bottom: 20px;
        }

        .card-title {
            font-size: 1.3rem;
            color: #2c3e50;
            font-weight: 600;
        }

        .metric-value {
            font-size: 2rem;
            font-weight: bold;
            color: #3498db;
        }

        .metric-value.warning {
            color: #f39c12;
        }

        .metric-value.danger {
            color: #e74c3c;
        }

        .chart-container {
            position: relative;
            height: 300px;
            margin-top: 15px;
        }

        .memory-details {
            display: flex;
            justify-content: space-around;
            margin: 15px 0;
            padding: 15px;
            background: #f8f9fa;
            border-radius: 10px;
        }

        .memory-detail {
            text-align: center;
        }

        .memory-detail-label {
            font-size: 0.85rem;
            color: #7f8c8d;
            margin-bottom: 5px;
        }

        .memory-detail-value {
            font-size: 1.1rem;
            font-weight: 600;
            color: #2c3e50;
        }

        .cores-grid {
            display: grid;
            grid-template-columns: repeat(auto-fit, minmax(80px, 1fr));
            gap: 10px;
            margin-top: 15px;
        }

        .core-item {
            background: #f8f9fa;
            padding: 10px;
            border-radius: 8px;
            text-align: center;
        }

        .core-label {
            font-size: 0.75rem;
            color: #7f8c8d;
            margin-bottom: 5px;
        }

        .core-value {
            font-size: 1rem;
            font-weight: 600;
            color: #2c3e50;
        }

        footer {
            text-align: center;
            color: rgba(255,255,255,0.8);
            margin-top: 30px;
            font-size: 0.9rem;
        }

        @media (max-width: 768px) {
            .dashboard {
                grid-template-columns: 1fr;
            }

            h1 {
                font-size: 1.8rem;
            }

            .card {
                padding: 15px;
            }
        }
    </style>
</head>
<body>
    <div class="container">
        <header>
            <h1>🔧 System Monitor</h1>
            <p>Real-time CPU and Memory Usage Dashboard</p>
            <div class="status">
                <div class="status-badge disconnected" id="connection-status">
                    ⚪ Disconnected
                </div>
                <div class="status-badge" id="update-interval">
                    ⏱️ Update: 2s
                </div>
                <div class="status-badge" id="last-update">
                    🕐 Last update: --
                </div>
            </div>
        </header>

        <main class="dashboard">
            <div class="card">
                <div class="card-header">
                    <div class="card-title">📊 CPU Usage</div>
                    <div class="metric-value" id="cpu-value">--%</div>
                </div>
                <div class="chart-container">
                    <canvas id="cpu-chart"></canvas>
                </div>
                <div class="cores-grid" id="cores-grid">
                    <!-- Core items will be populated dynamically -->
                </div>
            </div>

            <div class="card">
                <div class="card-header">
                    <div class="card-title">💾 Memory Usage</div>
                    <div class="metric-value" id="memory-value">--%</div>
                </div>
                <div class="memory-details">
                    <div class="memory-detail">
                        <div class="memory-detail-label">Total</div>
                        <div class="memory-detail-value" id="memory-total">--</div>
                    </div>
                    <div class="memory-detail">
                        <div class="memory-detail-label">Used</div>
                        <div class="memory-detail-value" id="memory-used">--</div>
                    </div>
                    <div class="memory-detail">
                        <div class="memory-detail-label">Free</div>
                        <div class="memory-detail-value" id="memory-free">--</div>
                    </div>
                </div>
                <div class="chart-container">
                    <canvas id="memory-chart"></canvas>
                </div>
            </div>
        </main>

        <footer>
            <p>Real-time system monitoring via WebSocket | Data updates every 2 seconds</p>
        </footer>
    </div>

    <script>
        // Configuration
        const MAX_DATA_POINTS = 30;
        const UPDATE_INTERVAL = 2000;

        // Chart.js defaults
        Chart.defaults.responsive = true;
        Chart.defaults.maintainAspectRatio = false;
        Chart.defaults.plugins.legend.display = false;

        // Initialize charts
        const cpuChart = new Chart(document.getElementById('cpu-chart'), {
            type: 'line',
            data: {
                labels: [],
                datasets: [{
                    label: 'CPU Usage %',
                    data: [],
                    borderColor: '#3498db',
                    backgroundColor: 'rgba(52, 152, 219, 0.1)',
                    borderWidth: 2,
                    fill: true,
                    tension: 0.4,
                    pointRadius: 0,
                    pointHoverRadius: 4
                }]
            },
            options: {
                scales: {
                    y: {
                        beginAtZero: true,
                        max: 100,
                        grid: {
                            color: 'rgba(0,0,0,0.1)'
                        }
                    },
                    x: {
                        grid: {
                            display: false
                        }
                    }
                },
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                return `CPU: ${context.parsed.y.toFixed(1)}%`;
                            }
                        }
                    }
                },
                animation: {
                    duration: 500
                }
            }
        });

        const memoryChart = new Chart(document.getElementById('memory-chart'), {
            type: 'line',
            data: {
                labels: [],
                datasets: [{
                    label: 'Memory Usage %',
                    data: [],
                    borderColor: '#e74c3c',
                    backgroundColor: 'rgba(231, 76, 60, 0.1)',
                    borderWidth: 2,
                    fill: true,
                    tension: 0.4,
                    pointRadius: 0,
                    pointHoverRadius: 4
                }]
            },
            options: {
                scales: {
                    y: {
                        beginAtZero: true,
                        max: 100,
                        grid: {
                            color: 'rgba(0,0,0,0.1)'
                        }
                    },
                    x: {
                        grid: {
                            display: false
                        }
                    }
                },
                plugins: {
                    tooltip: {
                        callbacks: {
                            label: function(context) {
                                return `Memory: ${context.parsed.y.toFixed(1)}%`;
                            }
                        }
                    }
                },
                animation: {
                    duration: 500
                }
            }
        });

        // Socket.io connection
        const socket = io();

        // Update connection status
        function updateConnectionStatus(connected) {
            const statusEl = document.getElementById('connection-status');
            if (connected) {
                statusEl.textContent = '🟢 Connected';
                statusEl.className = 'status-badge connected';
            } else {
                statusEl.textContent = '🔴 Disconnected';
                statusEl.className = 'status-badge disconnected';
            }
        }

        // Format bytes to human readable
        function formatBytes(bytes) {
            if (bytes === 0) return '0 B';
            const k = 1024;
            const sizes = ['B', 'KB', 'MB', 'GB', 'TB'];
            const i = Math.floor(Math.log(bytes) / Math.log(k));
            return parseFloat((bytes / Math.pow(k, i)).toFixed(2)) + ' ' + sizes[i];
        }

        // Update CPU display
        function updateCPU(data) {
            const cpuValue = document.getElementById('cpu-value');
            const overall = data.overall;

            cpuValue.textContent = overall.toFixed(1) + '%';

            // Color coding
            cpuValue.className = 'metric-value';
            if (overall > 80) {
                cpuValue.classList.add('danger');
            } else if (overall > 60) {
                cpuValue.classList.add('warning');
            }

            // Update chart
            const now = new Date().toLocaleTimeString();
            cpuChart.data.labels.push(now);
            cpuChart.data.datasets[0].data.push(overall);

            // Keep only last N data points
            if (cpuChart.data.labels.length > MAX_DATA_POINTS) {
                cpuChart.data.labels.shift();
                cpuChart.data.datasets[0].data.shift();
            }

            cpuChart.update('none');

            // Update cores grid
            const coresGrid = document.getElementById('cores-grid');
            coresGrid.innerHTML = '';
            data.cores.forEach(core => {
                const coreEl = document.createElement('div');
                coreEl.className = 'core-item';
                coreEl.innerHTML = `
                    <div class="core-label">Core ${core.core}</div>
                    <div class="core-value">${core.load.toFixed(1)}%</div>
                `;
                coresGrid.appendChild(coreEl);
            });
        }

        // Update Memory display
        function updateMemory(data) {
            const memoryValue = document.getElementById('memory-value');
            const usagePercent = data.usagePercent;

            memoryValue.textContent = usagePercent.toFixed(1) + '%';

            // Color coding
            memoryValue.className = 'metric-value';
            if (usagePercent > 90) {
                memoryValue.classList.add('danger');
            } else if (usagePercent > 75) {
                memoryValue.classList.add('warning');
            }

            // Update details
            document.getElementById('memory-total').textContent = formatBytes(data.total * 1024 * 1024);
            document.getElementById('memory-used').textContent = formatBytes(data.used * 1024 * 1024);
            document.getElementById('memory-free').textContent = formatBytes(data.free * 1024 * 1024);

            // Update chart
            const now = new Date().toLocaleTimeString();
            memoryChart.data.labels.push(now);
            memoryChart.data.datasets[0].data.push(usagePercent);

            // Keep only last N data points
            if (memoryChart.data.labels.length > MAX_DATA_POINTS) {
                memoryChart.data.labels.shift();
                memoryChart.data.datasets[0].data.shift();
            }

            memoryChart.update('none');
        }

        // Socket event handlers
        socket.on('connect', () => {
            console.log('Connected to server');
            updateConnectionStatus(true);
        });

        socket.on('disconnect', () => {
            console.log('Disconnected from server');
            updateConnectionStatus(false);
        });

        socket.on('metrics', (data) => {
            console.log('Received metrics:', data);

            updateCPU(data.cpu);
            updateMemory(data.memory);

            // Update last update time
            document.getElementById('last-update').textContent = 
                '🕐 Last update: ' + new Date().toLocaleTimeString();
        });

        // Handle connection errors
        socket.on('connect_error', (error) => {
            console.error('Connection error:', error);
            updateConnectionStatus(false);
        });

        // Cleanup on page unload
        window.addEventListener('beforeunload', () => {
            socket.disconnect();
        });
    </script>
</body>
</html>
